async (params, browser) => {
  // Open Airtable table
  await browser.open(`${params.table_url}`)

  // Wait for grid to load
  await browser.waitForSelector('.dataRow, [data-rowindex], .headerRow', 15000)

  // Let grid fully render
  await browser.wait(2000)

  // Update field values for specified row
  const result = await browser.evaluate(`const rowIndex = parseInt(params.row_index, 10); const fields = JSON.parse(params.field_values); const headers = []; document.querySelectorAll('.headerRow .header, .columnHeader, [data-columnid] .header, [role="columnheader"]').forEach(h => { headers.push(h.textContent?.trim() || ''); }); const allRows = document.querySelectorAll('.dataRow, [data-rowindex], [role="row"]:not(.headerRow)'); if (rowIndex < 0 || rowIndex >= allRows.length) throw new Error('Row index ' + rowIndex + ' out of range. Total rows: ' + allRows.length); const targetRow = allRows[rowIndex]; const updatedFields = []; for (const [fieldName, value] of Object.entries(fields)) { const colIndex = headers.findIndex(h => h.toLowerCase() === fieldName.toLowerCase()); if (colIndex === -1) { updatedFields.push({ field: fieldName, status: 'column_not_found' }); continue; } const cells = targetRow.querySelectorAll('.cell, [data-columnid], [role="gridcell"]'); const targetCell = cells[colIndex]; if (!targetCell) { updatedFields.push({ field: fieldName, status: 'cell_not_found' }); continue; } targetCell.click(); await new Promise(r => setTimeout(r, 500)); targetCell.dispatchEvent(new MouseEvent('dblclick', { bubbles: true })); await new Promise(r => setTimeout(r, 500)); const input = targetCell.querySelector('.cellInput, [contenteditable="true"], input, textarea') || document.activeElement; if (input) { if (input.contentEditable === 'true') { input.textContent = ''; input.textContent = String(value); input.dispatchEvent(new Event('input', { bubbles: true })); } else { const nativeSet = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set || Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, 'value').set; nativeSet.call(input, ''); input.dispatchEvent(new Event('input', { bubbles: true })); nativeSet.call(input, String(value)); input.dispatchEvent(new Event('input', { bubbles: true })); input.dispatchEvent(new Event('change', { bubbles: true })); } const oldValue = targetCell.textContent?.trim()?.substring(0, 100) || ''; updatedFields.push({ field: fieldName, status: 'updated', old_value: oldValue, new_value: String(value) }); } else { updatedFields.push({ field: fieldName, status: 'no_input_found' }); } await new Promise(r => setTimeout(r, 300)); } document.activeElement?.blur(); return { success: true, row_index: rowIndex, fields_processed: updatedFields.length, fields: updatedFields }`)

  return result
}
